-- TopicRelations

INSERT OR IGNORE INTO TopicRelations (topic_id, related_topic_id, relation_type, description_pl, description_ua, display_order, is_active)
SELECT src.id, tgt.id, 'PREREQUISITE', 'Wymagane wcześniejsze opanowanie (kolejność podręcznika).', 'Потрібне попереднє опанування (порядок підручника).', 1, 1
FROM Topics src, Topics tgt
WHERE src.code = 'MAT5-NUM-002' AND tgt.code = 'MAT5-NUM-001'
  AND NOT EXISTS (
    SELECT 1 FROM TopicRelations tr
    WHERE tr.topic_id = src.id AND tr.related_topic_id = tgt.id AND tr.relation_type = 'PREREQUISITE'
  );

