INSERT OR IGNORE INTO Lessons (code, subject_id, school_class, lesson_type, duration,
  title_pl, title_ua, goal_pl, goal_ua,
  learning_results_pl, learning_results_ua,
  terminology_pl, terminology_ua,
  scenario_pl, scenario_ua,
  homework_pl, homework_ua,
  assessment_pl, assessment_ua,
  author, version, status, is_active)
VALUES (
  'MAT5-001', 1, 5, 'New Knowledge', 45,
  'Działania pamięciowe', 'Дії усно',
  'Uczeń realizuje wymagania PP (I.1) w temacie „Działania pamięciowe".',
  'Учень реалізує вимоги PP (I.1) у темі «Дії усно».',
  '• Co uczeń powinien wiedzieć: Uczeń zna pojęcia i definicje z tematu „Działania pamięciowe”.
• Co uczeń powinien umieć: Uczeń stosuje wiedzę z tematu „Działania pamięciowe” w zadaniach podstawowych i rozszerzonych.
• Wymaganie PP (I.1): Uczeń wykonuje działania pamięciowe (dodawanie, odejmowanie, mnożenie, dzielenie) na liczbach naturalnych.', '• Що учень повинен знати: Учень знає поняття та визначення з теми «Дії усно».
• Що учень повинен вміти: Учень застосовує знання з теми «Дії усно» у базових і розширених завданнях.
• Вимога PP (I.1): Uczeń wykonuje działania pamięciowe (dodawanie, odejmowanie, mnożenie, dzielenie) na liczbach naturalnych.',
  'I.1; Działania; pamięciowe', 'I.1; Дії; усно',
  'I. WPROWADZENIE (10 min)
Aktywizacja wiedzy poprzedniej (• Wiedza z klasy 4 w zakresie matematyki).

II. GŁÓWNA CZĘŚĆ (25 min)
Realizacja tematu „Działania pamięciowe” — zgodnie ze spisem treści podręcznika kl. 5.
Praca: tablica, karta pracy, omówienie przykładów.

III. ĆWICZENIA (10 min)
Zadania z podręcznika i karty pracy — poziom podstawowy.

IV. PODSUMOWANIE (5 min)
Refleksja: co uczeń powinien wiedzieć i umieć po lekcji.',
  'I. ВСТУП (10 хв)
Активізація попередніх знань.

II. ОСНОВНА ЧАСТИНА (25 хв)
Реалізація теми «Дії усно» — згідно зі змістом підручника 5 класу.

III. ВПРАВИ (10 хв)
Завдання з підручника та робочого аркуша.

IV. ПІДСУМОК (5 хв)
Рефлексія: що учень повинен знати та вміти після уроку.',
  'Zadania domowe — sekcja „Działania pamięciowe” w podręczniku.',
  'Домашнє завдання — розділ «Дії усно» у підручнику.',
  'Obserwacja, krótka kartkówka lub samoocena.',
  'Спостереження, коротка картка або самооцінка.',
  'EduMost', '1.0', 'Draft', 1
);

